#pragma once
#define BATTERIES_BIT_OPS_INSERT_BIT_HPP

#include <batteries/config.hpp>
//
#include <batteries/bit_ops/set_bit.hpp>

#include <batteries/int_types.hpp>

namespace batt {

[[nodiscard]] constexpr inline u64 insert_bit(u64 bit_set, i32 index, bool value)
{
    const u64 lower_mask = (u64{1} << index) - 1;
    const u64 upper_mask = ~lower_mask;

    bit_set = (bit_set & lower_mask) | ((bit_set & upper_mask) << 1);
    bit_set = set_bit(bit_set, index, value);

    return bit_set;
}

template <usize N>
[[nodiscard]] constexpr inline std::array<u64, N> insert_bit(const std::array<u64, N>& bit_set, i32 index,
                                                             bool value)
{
    std::array<u64, N> output = bit_set;

    const i32 word_i = index / 64;
    const i32 bit_i = index % 64;

    u64 carry_bit = (bit_set[word_i] >> 63) & 1;

    output[word_i] = insert_bit(bit_set[word_i], bit_i, value);

    for (usize i = word_i + 1; i < N; ++i) {
        u64 next_carry_bit = (bit_set[i] >> 63) & 1;
        output[i] = (bit_set[i] << 1) | carry_bit;
        carry_bit = next_carry_bit;
    }

    return output;
}

}  //namespace batt
